package org.apache.commons.csv;

import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.apache.commons.csv.Constants;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.*;

class CSVPrinterPrintTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrint_nullValue_nullStringNull() throws IOException {
        when(format.getNullString()).thenReturn(null);

        printer.print(null);

        // Verify that print(Object, CharSequence, int, int) was called with Constants.EMPTY
        // We use reflection to verify internal call by spying on printer and intercepting private print
        CSVPrinter spyPrinter = Mockito.spy(printer);

        try {
            Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
            printMethod.setAccessible(true);

            spyPrinter.print(null);

            // We verify that print private method was called with Constants.EMPTY string
            verify(spyPrinter).print(eq(null), eq(Constants.EMPTY), eq(0), eq(Constants.EMPTY.length()));
        } catch (NoSuchMethodException | SecurityException e) {
            fail("Reflection setup failed: " + e.getMessage());
        }
    }

    @Test
    void testPrint_nullValue_nullStringNonNull() throws IOException {
        final String nullString = "NULLSTR";
        when(format.getNullString()).thenReturn(nullString);

        CSVPrinter spyPrinter = Mockito.spy(printer);

        try {
            Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
            printMethod.setAccessible(true);

            spyPrinter.print(null);

            verify(spyPrinter).print(eq(null), eq(nullString), eq(0), eq(nullString.length()));
        } catch (NoSuchMethodException | SecurityException e) {
            fail("Reflection setup failed: " + e.getMessage());
        }
    }

    @Test
    void testPrint_nonNullValue() throws IOException {
        String value = "value";

        CSVPrinter spyPrinter = Mockito.spy(printer);

        try {
            Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
            printMethod.setAccessible(true);

            spyPrinter.print(value);

            verify(spyPrinter).print(eq(value), eq(value), eq(0), eq(value.length()));
        } catch (NoSuchMethodException | SecurityException e) {
            fail("Reflection setup failed: " + e.getMessage());
        }
    }

    @Test
    void testPrint_privatePrint_invocation() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Test coverage for private print method called by public print

        String value = "abc";
        Method privatePrint = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        privatePrint.setAccessible(true);

        // Call private print directly
        privatePrint.invoke(printer, value, value, 0, value.length());

        // No exception means success; coverage for private print
    }
}
